     1→package api
     2→
     3→import (
     4→	"context"
     5→	"net/http"
     6→	"strings"
     7→
     8→	"github.com/sentioxyz/changelogue/internal/models"
     9→)
    10→
    11→// SourcesStore defines the persistence operations for sources.
    12→type SourcesStore interface {
    13→	ListSourcesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Source, int, error)
    14→	CreateSource(ctx context.Context, src *models.Source) error
    15→	GetSource(ctx context.Context, id string) (*models.Source, error)
    16→	UpdateSource(ctx context.Context, id string, src *models.Source) error
    17→	DeleteSource(ctx context.Context, id string) error
    18→}
    19→
    20→// SourcesHandler implements HTTP handlers for the /sources resource.
    21→type SourcesHandler struct {
    22→	store SourcesStore
    23→}
    24→
    25→// NewSourcesHandler returns a new SourcesHandler.
    26→func NewSourcesHandler(store SourcesStore) *SourcesHandler {
    27→	return &SourcesHandler{store: store}
    28→}
    29→
    30→// List handles GET /projects/{projectId}/sources — returns a paginated list of sources for a project.
    31→func (h *SourcesHandler) List(w http.ResponseWriter, r *http.Request) {
    32→	projectID := r.PathValue("projectId")
    33→	if projectID == "" {
    34→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    35→		return
    36→	}
    37→	page, perPage := ParsePagination(r)
    38→	sources, total, err := h.store.ListSourcesByProject(r.Context(), projectID, page, perPage)
    39→	if err != nil {
    40→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list sources")
    41→		return
    42→	}
    43→	if sources == nil {
    44→		sources = []models.Source{}
    45→	}
    46→	RespondList(w, r, http.StatusOK, sources, page, perPage, total)
    47→}
    48→
    49→// Create handles POST /projects/{projectId}/sources — creates a new source under a project.
    50→func (h *SourcesHandler) Create(w http.ResponseWriter, r *http.Request) {
    51→	projectID := r.PathValue("projectId")
    52→	if projectID == "" {
    53→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    54→		return
    55→	}
    56→	var src models.Source
    57→	if err := DecodeJSON(r, &src); err != nil {
    58→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    59→		return
    60→	}
    61→	src.ProjectID = projectID
    62→	src.Provider = strings.TrimSpace(src.Provider)
    63→	src.Repository = strings.TrimSpace(src.Repository)
    64→	if src.Provider == "" {
    65→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "provider is required")
    66→		return
    67→	}
    68→	if src.Repository == "" {
    69→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "repository is required")
    70→		return
    71→	}
    72→	if err := h.store.CreateSource(r.Context(), &src); err != nil {
    73→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create source")
    74→		return
    75→	}
    76→	RespondJSON(w, r, http.StatusCreated, src)
    77→}
    78→
    79→// Get handles GET /sources/{id} — returns a single source.
    80→func (h *SourcesHandler) Get(w http.ResponseWriter, r *http.Request) {
    81→	id := r.PathValue("id")
    82→	if id == "" {
    83→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
    84→		return
    85→	}
    86→	src, err := h.store.GetSource(r.Context(), id)
    87→	if err != nil {
    88→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
    89→		return
    90→	}
    91→	RespondJSON(w, r, http.StatusOK, src)
    92→}
    93→
    94→// Update handles PUT /sources/{id} — updates an existing source.
    95→func (h *SourcesHandler) Update(w http.ResponseWriter, r *http.Request) {
    96→	id := r.PathValue("id")
    97→	if id == "" {
    98→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
    99→		return
   100→	}
   101→	var src models.Source
   102→	if err := DecodeJSON(r, &src); err != nil {
   103→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   104→		return
   105→	}
   106→	src.Provider = strings.TrimSpace(src.Provider)
   107→	src.Repository = strings.TrimSpace(src.Repository)
   108→	if src.Provider == "" {
   109→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "provider is required")
   110→		return
   111→	}
   112→	if src.Repository == "" {
   113→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "repository is required")
   114→		return
   115→	}
   116→	if err := h.store.UpdateSource(r.Context(), id, &src); err != nil {
   117→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   118→		return
   119→	}
   120→	src.ID = id
   121→	RespondJSON(w, r, http.StatusOK, src)
   122→}
   123→
   124→// Delete handles DELETE /sources/{id} — deletes a source.
   125→func (h *SourcesHandler) Delete(w http.ResponseWriter, r *http.Request) {
   126→	id := r.PathValue("id")
   127→	if id == "" {
   128→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   129→		return
   130→	}
   131→	if err := h.store.DeleteSource(r.Context(), id); err != nil {
   132→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   133→		return
   134→	}
   135→	w.WriteHeader(http.StatusNoContent)
   136→}
