     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR, { mutate } from "swr";
     5→import Link from "next/link";
     6→import { Pencil, Trash2 } from "lucide-react";
     7→import { projects as projectsApi, sources as sourcesApi } from "@/lib/api/client";
     8→import { Card, CardContent } from "@/components/ui/card";
     9→import { Badge } from "@/components/ui/badge";
    10→import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
    11→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    12→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    13→import { SourceForm } from "@/components/sources/source-form";
    14→import type { Source } from "@/lib/api/types";
    15→
    16→interface SourceWithProject extends Source {
    17→  projectName?: string;
    18→}
    19→
    20→export default function SourcesPage() {
    21→  const { data: projectsData } = useSWR("projects-for-sources", () => projectsApi.list());
    22→
    23→  const { data: allSources, isLoading } = useSWR(
    24→    projectsData ? "all-sources" : null,
    25→    async () => {
    26→      if (!projectsData?.data?.length) return [];
    27→      const results = await Promise.all(
    28→        projectsData.data.map(async (p) => {
    29→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
    30→          return (res?.data ?? []).map((s) => ({ ...s, projectName: p.name }));
    31→        })
    32→      );
    33→      return results.flat() as SourceWithProject[];
    34→    }
    35→  );
    36→
    37→  const [editingSource, setEditingSource] = useState<SourceWithProject | null>(null);
    38→  const [deletingId, setDeletingId] = useState<string | null>(null);
    39→
    40→  return (
    41→    <div className="space-y-4">
    42→      <div>
    43→        <h1
    44→          style={{
    45→            fontFamily: "var(--font-fraunces)",
    46→            fontSize: "24px",
    47→            fontWeight: 700,
    48→            color: "#111113",
    49→          }}
    50→        >
    51→          Sources
    52→        </h1>
    53→        <p
    54→          className="mt-1 text-[13px] text-[#6b7280]"
    55→          style={{ fontFamily: "var(--font-dm-sans)" }}
    56→        >
    57→          Ingestion sources across all projects. Sources are managed within their project.
    58→        </p>
    59→      </div>
    60→      <Card>
    61→        <CardContent className="p-0">
    62→          {isLoading ? (
    63→            <div className="py-12 text-center text-muted-foreground">Loading...</div>
    64→          ) : (
    65→            <Table>
    66→              <TableHeader>
    67→                <TableRow>
    68→                  <TableHead>Repository</TableHead>
    69→                  <TableHead>Provider</TableHead>
    70→                  <TableHead>Project</TableHead>
    71→                  <TableHead>Poll Interval</TableHead>
    72→                  <TableHead>Last Polled</TableHead>
    73→                  <TableHead>Status</TableHead>
    74→                  <TableHead>Actions</TableHead>
    75→                </TableRow>
    76→              </TableHeader>
    77→              <TableBody>
    78→                {(allSources ?? []).map((source) => (
    79→                  <TableRow key={source.id}>
    80→                    <TableCell>
    81→                      <span className="font-mono text-sm">{source.repository}</span>
    82→                    </TableCell>
    83→                    <TableCell><Badge variant="outline">{source.provider}</Badge></TableCell>
    84→                    <TableCell>
    85→                      <Link href={`/projects/${source.project_id}`} className="text-primary hover:underline">
    86→                        {source.projectName ?? source.project_id}
    87→                      </Link>
    88→                    </TableCell>
    89→                    <TableCell className="text-sm">{source.poll_interval_seconds}s</TableCell>
    90→                    <TableCell className="text-sm text-muted-foreground">{source.last_polled_at ? new Date(source.last_polled_at).toLocaleString() : "Never"}</TableCell>
    91→                    <TableCell>
    92→                      {source.last_error ? (
    93→                        <Badge variant="destructive" className="text-xs">{source.last_error}</Badge>
    94→                      ) : (
    95→                        <Badge variant={source.enabled ? "default" : "secondary"}>{source.enabled ? "active" : "disabled"}</Badge>
    96→                      )}
    97→                    </TableCell>
    98→                    <TableCell>
    99→                      <div className="flex items-center gap-2">
   100→                        <button
   101→                          onClick={() => setEditingSource(source)}
   102→                          className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-[#f3f3f1] hover:text-[#111113]"
   103→                        >
   104→                          <Pencil className="h-4 w-4" />
   105→                        </button>
   106→                        <button
   107→                          onClick={() => setDeletingId(source.id)}
   108→                          className="rounded p-1 text-[#9ca3af] transition-colors hover:bg-red-50 hover:text-red-600"
   109→                        >
   110→                          <Trash2 className="h-4 w-4" />
   111→                        </button>
   112→                      </div>
   113→                    </TableCell>
   114→                  </TableRow>
   115→                ))}
   116→              </TableBody>
   117→            </Table>
   118→          )}
   119→        </CardContent>
   120→      </Card>
   121→
   122→      {/* Edit dialog */}
   123→      <Dialog open={!!editingSource} onOpenChange={(open) => { if (!open) setEditingSource(null); }}>
   124→        <DialogContent className="sm:max-w-lg">
   125→          <DialogHeader><DialogTitle>Edit Source</DialogTitle></DialogHeader>
   126→          {editingSource && (
   127→            <SourceForm
   128→              key={editingSource.id}
   129→              title="Edit Source"
   130→              initial={editingSource}
   131→              onSubmit={async (input) => { await sourcesApi.update(editingSource.id, input); }}
   132→              onSuccess={() => { setEditingSource(null); mutate("all-sources"); }}
   133→              onCancel={() => setEditingSource(null)}
   134→            />
   135→          )}
   136→        </DialogContent>
